mod blake3;

use std::env;
use std::fs::File;
use std::io::{self, BufRead, BufReader, Read, Write};
use std::path::Path;
use std::process::ExitCode;

use blake3::{Hasher, KEY_LEN};

// ============================================================================
// Argument parsing — mimics clap derive layout used by b3sum 1.8.4
// ============================================================================

#[derive(Default)]
struct Args {
    keyed: bool,
    derive_key: Option<String>,
    length: Option<u64>,
    seek: Option<u64>,
    num_threads: Option<u64>,
    no_mmap: bool,
    no_names: bool,
    raw: bool,
    tag: bool,
    check: bool,
    quiet: bool,
    files: Vec<String>,
    // Track what was provided on the CLI, in order — for Usage lines.
    provided_flags: Vec<&'static str>,
}

const FLAG_KEYED: &str = "--keyed";
const FLAG_DERIVE_KEY: &str = "--derive-key <CONTEXT>";
const FLAG_LENGTH: &str = "--length <LEN>";
const FLAG_SEEK: &str = "--seek <SEEK>";
const FLAG_NUM_THREADS: &str = "--num-threads <NUM>";
const FLAG_NO_MMAP: &str = "--no-mmap";
const FLAG_NO_NAMES: &str = "--no-names";
const FLAG_RAW: &str = "--raw";
const FLAG_TAG: &str = "--tag";
const FLAG_CHECK: &str = "--check";
const FLAG_QUIET: &str = "--quiet";

fn flag_short_name(flag: &str) -> &str {
    // Strip the placeholder part for the short representation used in some lines.
    // E.g. "--length <LEN>" -> "--length" when shown in error tip context.
    // But the canonical conflict-message form keeps the placeholder.
    flag.split_whitespace().next().unwrap_or(flag)
}

fn parse_u64(s: &str, flag: &str) -> Result<u64, ClapError> {
    match s.parse::<u64>() {
        Ok(n) => Ok(n),
        Err(e) => {
            let msg = if e.kind() == &std::num::IntErrorKind::PosOverflow
                || e.kind() == &std::num::IntErrorKind::NegOverflow
            {
                "number too large to fit in target type"
            } else {
                "invalid digit found in string"
            };
            Err(ClapError::InvalidValue {
                value: s.to_string(),
                flag: flag.to_string(),
                reason: msg.to_string(),
            })
        }
    }
}

enum ClapError {
    Unknown {
        arg: String,
    },
    NeedValue {
        flag: &'static str,
    },
    InvalidValue {
        value: String,
        flag: String,
        reason: String,
    },
    Conflict {
        first: &'static str,
        second: &'static str,
    },
    RequiredMissing {
        missing: Vec<&'static str>,
    },
}

// The Usage line shows program name (basename), then optional flags + FILE marker.
fn prog_name() -> String {
    let arg0 = env::args().next().unwrap_or_else(|| "b3sum".to_string());
    let p = Path::new(&arg0);
    p.file_name()
        .map(|f| f.to_string_lossy().to_string())
        .unwrap_or(arg0)
}

fn write_usage_line(stderr: &mut dyn Write, flags: &[&str], file_required: bool) {
    let mut s = String::new();
    s.push_str(&prog_name());
    if flags.is_empty() {
        s.push_str(" [OPTIONS]");
    } else {
        for f in flags {
            s.push(' ');
            s.push_str(f);
        }
    }
    if file_required {
        s.push_str(" <FILE>...");
    } else {
        s.push_str(" [FILE]...");
    }
    let _ = writeln!(stderr, "Usage: {}", s);
}

fn emit_clap_error(err: ClapError, args: &Args) {
    let mut stderr = io::stderr().lock();
    match err {
        ClapError::Unknown { arg } => {
            let _ = writeln!(stderr, "error: unexpected argument '{}' found", arg);
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "  tip: to pass '{}' as a value, use '-- {}'", arg, arg);
            let _ = writeln!(stderr);
            // Usage line: show all provided flags + [FILE]...
            write_usage_line(&mut stderr, &args.provided_flags, false);
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "For more information, try '--help'.");
        }
        ClapError::NeedValue { flag } => {
            let _ = writeln!(
                stderr,
                "error: a value is required for '{}' but none was supplied",
                flag
            );
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "For more information, try '--help'.");
        }
        ClapError::InvalidValue {
            value,
            flag,
            reason,
        } => {
            let _ = writeln!(
                stderr,
                "error: invalid value '{}' for '{}': {}",
                value, flag, reason
            );
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "For more information, try '--help'.");
        }
        ClapError::Conflict { first, second } => {
            let _ = writeln!(
                stderr,
                "error: the argument '{}' cannot be used with '{}'",
                first, second
            );
            let _ = writeln!(stderr);
            // Show only the FIRST flag in Usage (this matches observed clap behavior).
            // FILE is required if first flag is --keyed OR if positional already provided.
            let first_short = flag_short_name(first);
            let file_required =
                first_short == "--keyed" || !args.files.is_empty();
            write_usage_line(&mut stderr, &[first], file_required);
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "For more information, try '--help'.");
        }
        ClapError::RequiredMissing { missing } => {
            let _ = writeln!(
                stderr,
                "error: the following required arguments were not provided:"
            );
            for m in &missing {
                let _ = writeln!(stderr, "  {}", m);
            }
            let _ = writeln!(stderr);
            // Usage line: missing flags first (in struct order), then user flags
            let mut flags: Vec<&str> = Vec::new();
            for m in &missing {
                if *m != "<FILE>..." {
                    flags.push(m);
                }
            }
            for f in &args.provided_flags {
                if !flags.contains(f) {
                    flags.push(f);
                }
            }
            let file_required =
                missing.contains(&"<FILE>...") || !args.files.is_empty();
            write_usage_line(&mut stderr, &flags, file_required);
            let _ = writeln!(stderr);
            let _ = writeln!(stderr, "For more information, try '--help'.");
        }
    }
}

// Check if a long flag would conflict with already-set flags.
fn check_conflict(args: &Args, new_flag: &'static str) -> Option<ClapError> {
    let new_short = flag_short_name(new_flag);
    // Define conflict groups
    let check_conflicts = ["--keyed", "--derive-key", "--length", "--no-names", "--raw", "--tag"];

    let conflict_pairs: &[(&str, &[&str])] = &[
        ("--check", &check_conflicts),
        ("--keyed", &["--check", "--derive-key"]),
        ("--derive-key", &["--check", "--keyed"]),
        ("--length", &["--check"]),
        ("--no-names", &["--check"]),
        ("--raw", &["--check"]),
        ("--tag", &["--check"]),
    ];

    for (a, conflicts_with) in conflict_pairs {
        if new_short == *a {
            for c in *conflicts_with {
                if is_flag_set(args, c) {
                    // The earlier flag in cmdline order is the "first" one
                    let earlier = find_provided(args, c).unwrap_or(c);
                    return Some(ClapError::Conflict {
                        first: earlier,
                        second: new_flag,
                    });
                }
            }
        }
    }
    None
}

fn is_flag_set(args: &Args, short_name: &str) -> bool {
    match short_name {
        "--keyed" => args.keyed,
        "--derive-key" => args.derive_key.is_some(),
        "--length" => args.length.is_some(),
        "--seek" => args.seek.is_some(),
        "--num-threads" => args.num_threads.is_some(),
        "--no-mmap" => args.no_mmap,
        "--no-names" => args.no_names,
        "--raw" => args.raw,
        "--tag" => args.tag,
        "--check" => args.check,
        "--quiet" => args.quiet,
        _ => false,
    }
}

fn find_provided(args: &Args, short_name: &str) -> Option<&'static str> {
    args.provided_flags
        .iter()
        .find(|f| flag_short_name(f) == short_name)
        .copied()
}

fn mark_provided(args: &mut Args, flag: &'static str) {
    if !args.provided_flags.contains(&flag) {
        args.provided_flags.push(flag);
    }
}

// Parse a single long flag with optional inline =VALUE.
// Returns Some(value) if value follows, or None for boolean flags.
fn split_eq(s: &str) -> (&str, Option<&str>) {
    if let Some(idx) = s.find('=') {
        (&s[..idx], Some(&s[idx + 1..]))
    } else {
        (s, None)
    }
}

fn parse_args() -> Result<Args, ClapError> {
    let mut args = Args::default();
    let argv: Vec<String> = env::args().skip(1).collect();
    let mut i = 0;
    let mut positional_only = false;

    while i < argv.len() {
        let a = &argv[i];
        if positional_only {
            args.files.push(a.clone());
            i += 1;
            continue;
        }
        if a == "--" {
            positional_only = true;
            i += 1;
            continue;
        }
        if a == "-" || !a.starts_with('-') {
            args.files.push(a.clone());
            i += 1;
            continue;
        }
        if a.starts_with("--") {
            let (name, inline_val) = split_eq(a);
            match name {
                "--help" => {
                    print_help_full();
                    std::process::exit(0);
                }
                "--version" => {
                    print_version();
                    std::process::exit(0);
                }
                "--keyed" => {
                    if let Some(err) = check_conflict(&args, FLAG_KEYED) {
                        return Err(err);
                    }
                    args.keyed = true;
                    mark_provided(&mut args, FLAG_KEYED);
                }
                "--derive-key" => {
                    if let Some(err) = check_conflict(&args, FLAG_DERIVE_KEY) {
                        return Err(err);
                    }
                    let val = if let Some(v) = inline_val {
                        v.to_string()
                    } else {
                        i += 1;
                        if i >= argv.len() {
                            return Err(ClapError::NeedValue { flag: FLAG_DERIVE_KEY });
                        }
                        argv[i].clone()
                    };
                    args.derive_key = Some(val);
                    mark_provided(&mut args, FLAG_DERIVE_KEY);
                }
                "--length" => {
                    if let Some(err) = check_conflict(&args, FLAG_LENGTH) {
                        return Err(err);
                    }
                    let val = if let Some(v) = inline_val {
                        v.to_string()
                    } else {
                        i += 1;
                        if i >= argv.len() {
                            return Err(ClapError::NeedValue { flag: FLAG_LENGTH });
                        }
                        argv[i].clone()
                    };
                    let n = parse_u64(&val, FLAG_LENGTH)?;
                    args.length = Some(n);
                    mark_provided(&mut args, FLAG_LENGTH);
                }
                "--seek" => {
                    if let Some(err) = check_conflict(&args, FLAG_SEEK) {
                        return Err(err);
                    }
                    let val = if let Some(v) = inline_val {
                        v.to_string()
                    } else {
                        i += 1;
                        if i >= argv.len() {
                            return Err(ClapError::NeedValue { flag: FLAG_SEEK });
                        }
                        argv[i].clone()
                    };
                    let n = parse_u64(&val, FLAG_SEEK)?;
                    args.seek = Some(n);
                    mark_provided(&mut args, FLAG_SEEK);
                }
                "--num-threads" => {
                    if let Some(err) = check_conflict(&args, FLAG_NUM_THREADS) {
                        return Err(err);
                    }
                    let val = if let Some(v) = inline_val {
                        v.to_string()
                    } else {
                        i += 1;
                        if i >= argv.len() {
                            return Err(ClapError::NeedValue { flag: FLAG_NUM_THREADS });
                        }
                        argv[i].clone()
                    };
                    let n = parse_u64(&val, FLAG_NUM_THREADS)?;
                    args.num_threads = Some(n);
                    mark_provided(&mut args, FLAG_NUM_THREADS);
                }
                "--no-mmap" => {
                    if let Some(err) = check_conflict(&args, FLAG_NO_MMAP) {
                        return Err(err);
                    }
                    args.no_mmap = true;
                    mark_provided(&mut args, FLAG_NO_MMAP);
                }
                "--no-names" => {
                    if let Some(err) = check_conflict(&args, FLAG_NO_NAMES) {
                        return Err(err);
                    }
                    args.no_names = true;
                    mark_provided(&mut args, FLAG_NO_NAMES);
                }
                "--raw" => {
                    if let Some(err) = check_conflict(&args, FLAG_RAW) {
                        return Err(err);
                    }
                    args.raw = true;
                    mark_provided(&mut args, FLAG_RAW);
                }
                "--tag" => {
                    if let Some(err) = check_conflict(&args, FLAG_TAG) {
                        return Err(err);
                    }
                    args.tag = true;
                    mark_provided(&mut args, FLAG_TAG);
                }
                "--check" => {
                    if let Some(err) = check_conflict(&args, FLAG_CHECK) {
                        return Err(err);
                    }
                    args.check = true;
                    mark_provided(&mut args, FLAG_CHECK);
                }
                "--quiet" => {
                    args.quiet = true;
                    mark_provided(&mut args, FLAG_QUIET);
                }
                _ => {
                    return Err(ClapError::Unknown { arg: a.clone() });
                }
            }
            i += 1;
        } else {
            // Short flag(s): -xyz or -xVALUE
            let chars: Vec<char> = a[1..].chars().collect();
            let mut ci = 0;
            while ci < chars.len() {
                let c = chars[ci];
                match c {
                    'h' => {
                        print_help_short();
                        std::process::exit(0);
                    }
                    'V' => {
                        print_version();
                        std::process::exit(0);
                    }
                    'c' => {
                        if let Some(err) = check_conflict(&args, FLAG_CHECK) {
                            return Err(err);
                        }
                        args.check = true;
                        mark_provided(&mut args, FLAG_CHECK);
                    }
                    'l' => {
                        if let Some(err) = check_conflict(&args, FLAG_LENGTH) {
                            return Err(err);
                        }
                        // Value: rest of this token, or next arg
                        let val_str: String = if ci + 1 < chars.len() {
                            let v: String = chars[ci + 1..].iter().collect();
                            ci = chars.len();
                            v
                        } else {
                            i += 1;
                            if i >= argv.len() {
                                return Err(ClapError::NeedValue { flag: FLAG_LENGTH });
                            }
                            argv[i].clone()
                        };
                        let n = parse_u64(&val_str, FLAG_LENGTH)?;
                        args.length = Some(n);
                        mark_provided(&mut args, FLAG_LENGTH);
                    }
                    _ => {
                        // Unknown short flag → format as -X
                        let bad = format!("-{}", c);
                        return Err(ClapError::Unknown { arg: bad });
                    }
                }
                ci += 1;
            }
            i += 1;
        }
    }

    // Check requirements
    // --quiet requires --check, UNLESS one of the flags that conflict with --check is set
    let quiet_satisfied = args.check
        || args.keyed
        || args.derive_key.is_some()
        || args.length.is_some()
        || args.no_names
        || args.raw
        || args.tag;
    if args.quiet && !quiet_satisfied {
        let mut missing: Vec<&'static str> = Vec::new();
        missing.push(FLAG_CHECK);
        if args.keyed && args.files.is_empty() {
            missing.push("<FILE>...");
        }
        return Err(ClapError::RequiredMissing { missing });
    }
    // --keyed requires <FILE>...
    if args.keyed && args.files.is_empty() {
        let mut missing: Vec<&'static str> = Vec::new();
        missing.push("<FILE>...");
        return Err(ClapError::RequiredMissing { missing });
    }
    // Empty arg `""` is rejected as empty positional value
    if args.files.iter().any(|f| f.is_empty()) {
        let mut stderr = io::stderr().lock();
        let _ = writeln!(
            stderr,
            "error: a value is required for '[FILE]...' but none was supplied"
        );
        let _ = writeln!(stderr);
        let _ = writeln!(stderr, "For more information, try '--help'.");
        std::process::exit(2);
    }

    Ok(args)
}

// ============================================================================
// Help text
// ============================================================================

fn print_version() {
    println!("b3sum 1.8.4");
}

fn print_help_short() {
    let p = prog_name();
    println!("Usage: {} [OPTIONS] [FILE]...", p);
    println!();
    println!("Arguments:");
    println!("  [FILE]...  Files to hash, or checkfiles to check");
    println!();
    println!("Options:");
    println!("      --keyed                 Use the keyed mode, reading the 32-byte key from stdin");
    println!("      --derive-key <CONTEXT>  Use the key derivation mode, with the given context string");
    println!("  -l, --length <LEN>          The number of output bytes, before hex encoding [default: 32]");
