// Check if a long flag would conflict with already-set flags.
fn check_conflict(args: &Args, new_flag: &'static str) -> Option<ClapError> {
    let new_short = flag_short_name(new_flag);
    // Define conflict groups
    let check_conflicts = ["--keyed", "--derive-key", "--length", "--no-names", "--raw", "--tag"];

    let conflict_pairs: &[(&str, &[&str])] = &[
        ("--check", &check_conflicts),
        ("--keyed", &["--check", "--derive-key"]),
        ("--derive-key", &["--check", "--keyed"]),
        ("--length", &["--check"]),
        ("--no-names", &["--check"]),
        ("--raw", &["--check"]),
        ("--tag", &["--check"]),
    ];

    for (a, conflicts_with) in conflict_pairs {
        if new_short == *a {
            for c in *conflicts_with {
                if is_flag_set(args, c) {
                    // The earlier flag in cmdline order is the "first" one
                    let earlier = find_provided(args, c).unwrap_or(c);
                    return Some(ClapError::Conflict {
                        first: earlier,
                        second: new_flag,
                    });
                }
            }
        }
    }
    None
}

