        "--length",
        "--seek",
        "--num-threads",
        "--no-mmap",
        "--no-names",
        "--raw",
        "--tag",
        "--check",
        "--quiet",
        "--help",
        "--version",
    ];
    let mut best: (f64, &'static str) = (0.0, "");
    for c in candidates {
        let score = jaro_winkler(unknown, c);
        if score > best.0 {
